+	if !ok {
+		return 0, false
+	}
+	payloadB64, _, ok = strings.Cut(payloadB64, ".")
+	if !ok {
+		return 0, false
+	}
+	payload, err := base64.RawURLEncoding.DecodeString(payloadB64)
+	if err != nil {
+		return 0, false
+	}
