+		Expires int64 `json:"expires"`
+	}
+	if err := json.Unmarshal(payload, &v); err != nil {
+		return 0, false
+	}
+	exp := v.Exp
+	if exp <= 0 {
+		exp = v.Expires
+	}
+	if exp <= 0 {
+		return 0, false
+	}
+	return exp, true
